const items = $input.all();
const wf = $('Ejecutar Workflow').first().json;
const busqueda = (wf.busqueda ?? '').trim();
const soloUltimo = String(wf.solo_ultimo ?? '').toLowerCase() === 'true';

// Detect empty result (postgres node with alwaysOutputData outputs 1 empty item when 0 rows)
const rows = (items.length === 1 && !items[0].json.proceso_id) ? [] : items;

if (rows.length === 0) {
  return [{ json: { resultado: `🔍 No se encontraron procesos para el inmueble "${busqueda}". Verifica el código o la dirección.` } }];
}

// Group rows by property_id
const propMap = {};
rows.forEach(it => {
  const r = it.json;
  const pid = r.property_id;
  if (!propMap[pid]) {
    propMap[pid] = {
      code: r.property_code,
      address: r.property_address,
      status: r.property_status,
      processes: []
    };
  }
  propMap[pid].processes.push(r);
});

const props = Object.values(propMap);

// Multiple properties → ask for clarification
if (props.length > 1) {
  const lista = props.map((p, i) =>
    `${i + 1}. *${p.code}* - ${p.address} (${p.processes.length} proceso(s))`
  ).join('\n');
  return [{
    json: {
      resultado: `🏠 Encontré ${props.length} inmuebles en "${busqueda}" con procesos:\n\n${lista}\n\n👉 Indícame el código exacto para ver el detalle de sus procesos (ej: 002).`
    }
  }];
}

// Single property → show timeline
const prop = props[0];
const procesos = soloUltimo ? [prop.processes[0]] : prop.processes;

const lines = [
  `📋 *Historial de Procesos — Inmueble ${prop.code}*`,
  `📍 ${prop.address} | Estado: ${prop.status}`,
  `📦 Total registrado: ${prop.processes.length} proceso(s)${soloUltimo ? ' (mostrando el más reciente)' : ''}`,
  ''
];

procesos.forEach((p, i) => {
  const fecha = new Date(p.created_at).toLocaleDateString('es-EC', {
    day: '2-digit', month: 'long', year: 'numeric'
  });
  lines.push(`${soloUltimo ? '🕐' : ('*' + (i + 1) + '.*')} *${p.title}*`);
  lines.push(`   👤 Parte: ${p.type}`);
  lines.push(`   📝 ${p.description}`);
  if (p.next_step) lines.push(`   ➡️ Siguiente paso: ${p.next_step}`);
  if (p.approximate_time) lines.push(`   ⏱️ Duración estimada: ${p.approximate_time}`);
  if (p.expenses && Array.isArray(p.expenses) && p.expenses.length > 0) {
    const totalGastos = p.expenses.reduce((acc, e) => acc + Number(e.amount || 0), 0);
    const detalleGastos = p.expenses.map(e => `$${e.amount} - ${e.description}`).join(', ');
    lines.push(`   💰 Gastos: ${detalleGastos} (Total: $${totalGastos})`);
  }
  lines.push(`   📅 ${fecha}`);
  lines.push('');
});

return [{ json: { resultado: lines.join('\n') } }];
